        ID_7403                                                               = 7403,  -- @@
        TEMPLE_KNIGHTS_OF_SAN_D_ORIA_FRIEND_WE                                = 7404,  -- Temple Knights of San d'Oria, friend. We're conducting rescue drills in this valley. You're free to go down; just stay out of the way.
        RESCUE_DRILLS_IN_PROGRESS_TRY_TO_STAY_OUT                             = 7405,  -- Rescue drills in progress. Try to stay out of the way.
        SORRY_NO_TIME_TO_CHAT_I_M_A                                           = 7406,  -- Sorry, no time to chat. I'm a little busy right now.
        NOTHING_TO_REPORT                                                     = 7407,  -- Nothing to report.
        HEAD_DOWN_HERE_IF_YOU_WISH_TO_TAKE                                    = 7408,  -- Head down here if you wish to take part in the rescue drill.
        THEY_RE_CONDUCTING_DRILLS_UP_AHEAD_AT_LEAST                           = 7409,  -- They're conducting drills up ahead... At least, I think they are.
        SIR_WE_VE_LOOKED_EVERYWHERE_WITH_NO_LUCK                              = 7410,  -- Sir! We've looked everywhere, with no luck so far!
        ONE_OF_THE_INJURED_SOLDIERS_HAS_GONE_MISSING                          = 7411,  -- One of the injured soldiers has gone missing! Well, don't just stand there! Help us search!
        WELL_FIND_ANYTHING                                                    = 7412,  -- Well? Find anything?
        NO_NOTHING_SIR                                                        = 7413,  -- No, nothing, sir!
        HE_S_NOT_HERE_WE_LL_HAVE_TO                                           = 7414,  -- He's not here. We'll have to spread out and try to cover more ground.
        WELL_ANY_SIGN_OF_HIM                                                  = 7415,  -- Well? Any sign of him?
        WHAT_COULD_HAVE_HAPPENED_TO_HIM                                       = 7416,  -- What could have happened to him!?
        HEY                                                                   = 7417,  -- Hey!
        HEY_COME_TAKE_A_LOOK_AT_THIS_QUICKLY                                  = 7418,  -- Hey! Come take a look at this! Quickly!
        LOOK_A_CAVE_MAYBE_HE_WENT_IN_THERE                                    = 7419,  -- Look, a cave! Maybe he went in there!
        ARE_YOU_IN_THE_RESCUE_DRILL                                           = 7420,  -- Are you in the rescue drill?
        HEAD_TO_THE_OTHER_SIDE_OF_THAT_VALLEY                                 = 7421,  -- Head to the other side of that valley over there. One of my compatriots will assist you.
        GREETINGS_I_M_VICORPASSE_SQUAD_CAPTAIN_IN_THE                         = 7422,  -- Greetings. I'm Vicorpasse, squad captain in the Temple Knights.
        WE_ARE_SUPPOSED_TO_BE_CONDUCTING_RESCUE_DRILLS                        = 7423,  -- We are supposed to be conducting rescue drills, but one of our injured soldiers has gone missing. Your assistance in finding him would be appreciated.
        THE_MISSING_SOLDIER_IS_A_NEW_RECRUIT_BY                               = 7424,  -- The missing soldier is a new recruit by the name of Ruillont. I just hope nothing's happened to him...
        THE_SAN_D_ORIA_TEMPLE_KNIGHTS_ARE_CONDUCTING                          = 7425,  -- The San d'Oria Temple Knights are conducting drills in this area. Daily training is essential for the maintenance of an able fighting force, you know.
        RUILLONT_S_SWORD_DON_T_LOOK_AT_ME                                     = 7426,  -- Ruillont's sword? Don't look at me; I've nothing of the sort!
        RUILLONT_S_SWORD_YES_I_WAS_KEEPING_IT                                 = 7427,  -- Ruillont's sword? Yes, I was keeping it for him during training.
        WHAT_RUILLONT_S_STUCK_IN_A_CAVE_HOW                                   = 7428,  -- What, Ruillont's stuck in a cave? How typical of him to refuse your help...
        YES_I_BELIEVE_YOU_I_M_SURE_IT                                         = 7429,  -- Yes, I believe you; I'm sure it's him. Take this to him in there, would you? We'll keep it between you and me.
        DIDN_T_I_GIVE_YOU_HIS_SWORD_JUST                                      = 7430,  -- Didn't I give you his sword? Just hand it to Ruillont. Don't you lose it!
        WHAT_RUILLONT_S_IN_THAT_CAVE_AND_HE                                   = 7431,  -- What? Ruillont's in that cave? And he doesn't want us to send help, eh? That's my boy! He's an elite in the making, that one!
        WELL_THE_RESCUE_TRAINING_WAS_A_WASH_BUT                               = 7432,  -- Well, the rescue training was a wash, but you helped us find our lost soldier. I think you've earned this %.
        NO_REALLY_THESE_DRILLS_ARE_NAUGHT_COMPARED_TO                         = 7433,  -- No, really. These drills are naught compared to venturing into one of those caves. Hand that certificate to the knight at the gatehouse, and you'll be done.
        DON_T_FORGET_TO_TAKE_THE_TO_THE                                       = 7434,  -- Don't forget to take the % to the knight at the gatehouse.
        AH_IT_S_YOU_AGAIN_MY_MEN_AND                                          = 7435,  -- Ah, it's you again! My men and I thank you for your help.
        THEY_CANCELED_THE_RESCUE_DRILL_FUNNY_HOW_NO                           = 7436,  -- They canceled the rescue drill. Funny how no one's come back up yet...
        TRAINING_FINISHED_A_WHILE_AGO_AND_STILL_NO                            = 7437,  -- Training finished a while ago, and still no one. Something's fishy, here.
        NOT_HERE                                                              = 7438,  -- Not here...
        WELL_YOU_FIND_IT                                                      = 7439,  -- Well? You find it!?
        NO_GOOD_THERE_S_NOTHING_HERE_AT_ALL                                   = 7440,  -- No good. There's nothing here at all...
        OUR_CAPTAIN_SURE_LIKES_TO_GIVE_ORDERS_BUT                             = 7441,  -- Our captain sure likes to give orders, but I don't see him lifting a finger...
        HEY_IT_S_NOT_HERE_EITHER                                              = 7442,  -- Hey! It's not here, either!
        AH_YOU_AGAIN_NOTHING_FOR_YOU_TO_WORRY                                 = 7443,  -- Ah, you again. Nothing for you to worry about, j-just move right along.
        THOSE_MEN_SHOULD_HAVE_BEEN_BACK_FROM_TRAINING                         = 7444,  -- Those men should have been back from training by now... I wonder what's keeping them?
        GREETINGS_TRAVELER_SORRY_I_VE_LITTLE_TIME_TO                          = 7445,  -- Greetings. traveler. Sorry, I've little time to chat. I must focus on my prayer.
        AH_THE_THANK_YOU_FOR_MAKING_SUCH_A                                    = 7446,  -- Ah, the %! Thank you for making such a long journey to bring this! May the Gates of Paradise open to all.
        PLEASE_DELIVER_THAT_TO_THE_HIGH_PRIEST_IN                             = 7447,  -- Please deliver that % to the high priest in the San d'Oria Cathedral.
        MY_THANKS_AGAIN_FOR_YOUR_SERVICES_MAY_THE                             = 7448,  -- My thanks again for your services. May the Gates of Paradise open to all.
        YOU_SEE_A_MESSAGE_ENGRAVED_ON_THE_STONE                               = 7449,  -- You see a message engraved on the stone:
        THIS_PLATEAU_IS_A_LAND_OF_MANY_FEATURES                               = 7450,  -- This plateau is a land of many features, but by far the most memorable is the Crag of Holla.
        I_CALL_IT_A_STRUCTURE_FOR_I_HAVE                                      = 7451,  -- I call it a structure, for I have no other word. It is surely not a rock born of nature, nor does it seem to be a hall built by the gods, as the priestly scholars say.
        YET_THERE_ARE_NO_SEAMS_IN_ITS_BONE                                    = 7452,  -- Yet there are no seams in its bone-white surface, and it is faintly warm to the touch. But through a fortunate accident, I have found proof of its artificial origins.
        I_SHALL_HEAD_NORTH_TO_THE_LAND_OF                                     = 7453,  -- I shall head north to the land of Valdeaunia to verify my findings. I fear this may be the longest, most perilous journey of my life.
        I_LEAVE_MY_DAUGHTER_ENID_TO_FIND_HER                                  = 7454,  -- I leave my daughter Enid to find her own path. May the gods watch over her in my stead. --Gwynham Ironheart, 764 Crystal Era.
        ID_11ME                                                               = 7455,  -- 11Me%
        TH_M_L_B                                                              = 7456,  -- tH%M%L{#>B
        WOI_M_L_GHB                                                           = 7457,  -- WOi%M%L{#>)gHB
