        THERE_IS_NOTHING_TO_FEAR_PLEASE_LET_PHILLONE                          = 7733,  -- There is nothing to fear. Please let Phillone know that I need no thanks; I already have my reward. I am the Obsidian Bolt, such deeds are my reason for living...!
        WE_HAVE_YOU_NOW_THIEF_SURRENDER_QUIETLY                               = 7734,  -- We have you now, thief! Surrender quietly!
