        OH_WELL_IF_THAT_S_THE_CASE_I                                          = 7758,  -- Oh... Well, if that's the case, I'm outta here.
        THE_GOBLIN_SLIPPED_AWAY_WHEN_YOU_WERE_NOT                             = 7759,  -- The Goblin slipped away when you were not looking...
