        AS_I_HAVE_NO_STRENGTH_FOR_BATTLE_THIS                                 = 7835,  -- As I have no strength for battle, this is the best that I can do... But I am sure you will find it helpful.
        CARBUNCLE_WE_ARE_IN_YOUR_DEBT                                         = 7836,  -- Carbuncle! We are in your debt!
        THIS_IS_THE_FIRST_TERRESTRIAL_AVATAR_TO_AID                           = 7837,  -- %! This is the first terrestrial avatar to aid us in our cause. For the others, it will be welcome news indeed!
        BUT_FIRST_WE_MUST_SECURE_THE_ENERGY_THAT                              = 7838,  -- But first we must secure the energy that is sealed within the ruins of Pso'Xja. Let us rendezvous before the gate of Carbuncle!
        THE_NEST_S_OWNER_APPEARS_IN_A_FLURRY                                  = 7839,  -- The nest's owner appears in a flurry of rage!
        THERE_IS_A_BROKEN_EGG_ON_THE_GROUND                                   = 7840,  -- There is a broken egg on the ground here. Perhaps there is a nest in the boughs of this tree.
        NO_MORE_GOODIES_ROUND_HERE_ME_GO_LOOKS                                = 7841,  -- No more goodies 'round here! Me go looks somewheres else!
