        THE_TABS_YOU_ACQUIRE_CAN_BE_SPENT_ON                                  = 11167,  -- The tabs you acquire can be spent on field support.
        WHICH_ONE_YOU_HAVE_NOTHING_FOR_NOW_REPATRIATION                       = 11168,  -- Which one? (You have # [tab/tabs]). Nothing for now. Repatriation (#). White magic: Reraise (#). White magic: Regen (#). White magic: Refresh (#). White magic: Protect (#). White magic: Shell (#). Field recipe: Dried Meat (#). Field recipe: Salted Fish (#). Field recipe: Hard Cookie (#). Field recipe: Instant Noodles (#). Receive alter ego: Sakura. (#). Receive alter ego: Koru-Moru. (#).
        ARE_YOU_CERTAIN_YES_NO                                                = 11169,  -- Are you certain? Yes. No.
        RETURN_TO_YOUR_HOME_NATION_YES_NO                                     = 11170,  -- Return to your home nation? Yes. No.
        YOU_DO_NOT_HAVE_ENOUGH_TABS                                           = 11171,  -- You do not have enough tabs.
        IS_FULL_AND_CANNOT_EAT_ANYTHING_RIGHT_NOW                             = 11172,  -- % is full and cannot eat anything right now.
        YOU_MUST_WAIT_LONGER_BEFORE_YOU_ARE_ABLE                              = 11173,  -- You must wait longer before you are able to register a new training regime. It is recommended that you use this time to recuperate.
        WHICH_ONE_YOU_HAVE_NOTHING_FOR_NOW_READ                               = 11174,  -- Which one? (You have # [tab/tabs]). Nothing for now. Read instructions. %(#). %(#). %(#). %(#). %(#). %(#). %(#). %(#).
        ELITE_TRAINING_IS_A_SECTION_OF_THE_FIELD                              = 11175,  -- Elite training is a section of the Field Manual which caters to dauntless adventurers who wish to engage in a more grueling test of their mettle.
        TO_PARTICIPATE_IN_ELITE_TRAINING_REGIMES_YOU_MUST                     = 11176,  -- To participate in elite training regimes, you must acquire chapter transcripts, for which tabs are required.
        TRADING_GIL_OR_A_PIECE_OF_EQUIPMENT_AT                                = 11177,  -- Trading %, gil, or a piece of equipment at designated locations (while in possession of a chapter transcript) will trigger the commencement of your training.
        TRADED_ITEMS_WILL_NOT_BE_RETURNED_TO_YOU                              = 11178,  -- Traded items will not be returned to you. You will, however, be furnished with rewards of correlating value upon the successful completion of each elite training regime.
        EVEN_WITHIN_ELITE_TRAINING_THERE_ARE_REGIMES_OF                       = 11179,  -- Even within elite training, there are regimes of varying difficulty. The trade limit for each succeeding chapter will be greater than the last, and the training objective more challenging. For safety reasons, all participants are recommended to be well prepared.
        LASTLY_WE_AT_THE_A_M_A_N                                              = 11180,  -- Lastly, we at the A.M.A.N. recognize the importance of rest and recuperation as part of a healthy adventuring lifestyle. Therefore, a mandatory cool-down period will be imposed upon all adventurers following the completion of an elite training regime. Until this time has elapsed, you will be unable to undertake further training, even if a chapter transcript is in your possession.
        YOU_ALREADY_POSSESS                                                   = 11181,  -- You already possess %.
        YOU_CANNOT_UNDERTAKE_A_TRAINING_REGIME_WHILE_A                        = 11182,  -- You cannot undertake a training regime while a hunt is active.
        CANCEL_HUNT_YES_NO                                                    = 11183,  -- Cancel hunt? Yes. No.
        HUNT_CANCELED                                                         = 11184,  -- Hunt canceled.
        THE_REQUISITE_TIME_HAS_NOT_YET_ELAPSED_SINCE                          = 11185,  -- The requisite time has not yet elapsed since undertaking your last regime. You may be ineligible to receive gil and tab rewards.
        SET_TRAINING_REGIME_TO_AUTOMATICALLY_REPEAT_UPON_COMPLETION           = 11186,  -- Set training regime to automatically repeat upon completion?
        SET_TRAINING_REGIME_TO_REPEAT_YES_NO                                  = 11187,  -- Set training regime to repeat? Yes. No.
        YOU_VE_RECOVERED_ONE_OF_THE_LONG_LOST                                 = 11188,  -- You've recovered one of the long-lost mog tablets! You should share the news of your discovery with the Explorer Moogle in Ru'Lude Gardens.
        GREETINGS_ADVENTURER_YOU_VE_HEARD_THE_TALE_OF                         = 11189,  -- Greetings, adventurer! You've heard the tale of the mog tablets, haven't you? If any of them turn up in your travels, promise you'll let me know, kupo!
        MY_ADVENTURING_FRIEND_THANKS_TO_YOUR_EFFORTS_THE                      = 11190,  -- [Greetings/Happy Vana'versary], my adventuring friend! Thanks to your efforts, the mog tablets have been recovered, and their magic freed to spread happiness and joy across the realm! You are truly a friend to all mooglekind, kupo!
        OH_NO_WHAT_A_SHAME_KUPO_THE_MOG                                       = 11191,  -- Oh no! What a shame, kupo! The mog tablets that were recovered have been scattered to the ends of Vana'diel once more...
        ASK_ABOUT_SOMETHING_WHAT_S_A_MOG_TABLET                               = 11192,  -- Ask about something? What's a mog tablet? The history of mog tablets. List of tablets. Nothing.
        ASK_ABOUT_SOMETHING_WHAT_S_A_MOG_TABLET_2                             = 11193,  -- Ask about something? What's a mog tablet? The history of mog tablets. Collected tablets. The current Super Kupower. Nothing.
        ASK_ABOUT_SOMETHING_WHAT_S_A_MOG_TABLET_3                             = 11194,  -- Ask about something? What's a mog tablet? The history of mog tablets. Nothing.
        WHAT_S_A_MOG_TABLET_WHAT_S_A                                          = 11195,  -- What's a mog tablet!? What's a mog tablet, you say!? Why, only the most awesome, amazing artifact in the annals of moogle history, that's what, kupo!
        THERE_S_ELEVEN_OF_THEM_IN_ALL_TO                                      = 11196,  -- There's eleven of them in all, to be exact, scattered to the far reaches of Vana'diel and just waiting to be discovered by brave adventurers like you!
        WHAT_HAPPENS_IF_YOU_FIND_THEM_I_THOUGHT                               = 11197,  -- What happens if you find them? I thought you'd never ask, kupo! Each tablet is inscribed with an ancient moogle poem of joy, and legend has it that if all are found, the ancient moogle magic of King Kupofried the Great will be released once more, spreading joy and happiness through all the land!
        WE_EXPLORER_MOOGLES_HAVE_MADE_IT_OUR_LIFE                             = 11198,  -- We explorer moogles have made it our life's work to recover the tablets and unlock their powers. But with these short legs and little-bitty wings, we can't do it alone, kupo!
        THERE_I_VE_WHIPPED_UP_A_SPELL_THAT                                    = 11199,  -- There! I've whipped up a spell that will instantly transport any tablets you find back here to me. Come back if you find anything, and happy exploring, kupo!
        JUST_SIT_RIGHT_BACK_AND_I_LL_TELL                                     = 11200,  -- Just sit right back and I'll tell you the tale, kupo. Many, many ages past, we moogles had our own glorious kingdom. It was truly the peak of moogle civilization, a veritable golden age for all mooglekind!
        THE_SEVENTH_KING_OF_THIS_GREAT_NATION_WAS                             = 11201,  -- The seventh king of this great nation was the wise and kindly King Kupofried, a masterful magician famed as the father of the fantastic moogle magic that survives to this very day, kupo!
        IN_HIS_LATER_YEARS_KING_KUPOFRIED_EMBARKED_ON                         = 11202,  -- In his later years, King Kupofried embarked on what would become the greatest work of his illustrious reign. Seeking to pass down the prosperity of his kingdom to future generations, he inscribed eleven incantations of moogle joy and happiness onto eleven stone tablets.
        SADLY_THE_KINDLY_KING_S_INTENTIONS_WENT_UNAPPRECIATED                 = 11203,  -- Sadly, the kindly king's intentions went unappreciated by his selfish sons and daughters, and many a fierce feud broke out over who would inherit these relics, kupo...
        KING_KUPOFRIED_WAS_GREATLY_DISMAYED_HOW_COULD_THE                     = 11204,  -- King Kupofried was greatly dismayed. How could the poems that he had composed out of pure love and joy become the root of such strife?
        IN_HIS_DESPAIR_THE_KING_COMMANDED_HIS_MINION                          = 11205,  -- In his despair, the king commanded his minion bats to scatter the tablets to the far corners of the world, where they would be seen by moogle eyes no more.
        ALAS_I_ONLY_WANTED_MY_CHILDREN_TO_BE                                  = 11206,  -- Alas! I only wanted my children to be happy, kupo, he lamented, and flew away on his tiny yet majestic wings, never to be seen in his kingdom again.
        LEFT_WITHOUT_ITS_WISE_MONARCH_THE_ONCE_GLORIOUS                       = 11207,  -- Left without its wise monarch, the once-glorious moogle kingdom fractured into warring tribes, falling into unrest...and, eventually, ruin. A tragic tale, don't you think, kupo?
        WE_EXPLORER_MOOGLES_ARE_THE_PROUD_DESCENDANTS_OF                      = 11208,  -- We explorer moogles are the proud descendants of King Kupofried, living only to bring our last great monarch's unrealized dream to fruition. We will--we must!--find the mog tablets and bring true joy and happiness to this world!
        LET_S_SEE_IT_APPEARS_THAT_MOOGLE_ALREADY                              = 11209,  -- Let's see... It appears that # moogle [tablet has/tablets have] already been found, kupo.
        HERE_S_A_LIST_OF_ALL_THE_LOCATED                                      = 11210,  -- Here's a list of all the located tablets, kupo!
        CHOOSE_A_LOCATION_WEST_RONFAURE_EAST_RONFAURE_LA                      = 11211,  -- Choose a location: West Ronfaure. East Ronfaure. La Theine Plateau. Valkurm Dunes. Jugner Forest. Batallia Downs. North Gustaberg. South Gustaberg. Konschtat Highlands. Pashhow Marshlands. Rolanberry Fields. Beaucedine Glacier. Xarcabard. West Sarutabaruta. East Sarutabaruta. Tahrongi Canyon. Buburimu Peninsula. Meriphataud Mountains. Sauromugue Champaign. Qufim Island. Behemoth's Dominion. Cape Teriggan. Eastern Altepa Desert. The Sanctuary of Zi'Tah. Ro'Maeve. Yuhtunga Jungle. Yhoator Jungle. Western Altepa Desert. Valley of Sorrows. Cancel.
        THE_TABLET_OF_WAS_DISCOVERED_THERE_BY_KUPO                            = 11212,  -- The tablet of [temperance/fortitude/piety/justice/hope/wisdom/compassion/dignity/loyalty/charity/courage] was discovered there by %, kupo!
        THE_TABLET_OF_WAS_DISCOVERED_THERE_KUPO                               = 11213,  -- The tablet of [temperance/fortitude/piety/justice/hope/wisdom/compassion/dignity/loyalty/charity/courage] was discovered there, kupo!
        NO_TABLET_HAS_BEEN_DISCOVERED_THERE_YET_IT                            = 11214,  -- No tablet has been discovered there yet. It's not too late for you to stake your claim, kupo!
        OH_GLORIOUS_DAY_ALL_ELEVEN_MOG_TABLETS_HAVE                           = 11215,  -- Oh, glorious day! All eleven mog tablets have been recovered and restored to their rightful place at the altar of King Kupofried!
        CAN_YOU_FEEL_THE_ANCIENT_MOOGLE_MAGIC_IN                              = 11216,  -- Can you feel the ancient moogle magic in the air? You can now bask in the benefits of this Super Kupower...
        THRIFTY_TRANSIT_A_SPECIAL_TREAT_FOR_THE_COST                          = 11217,  -- Thrifty Transit! A special treat for the cost-conscious adventurer! For a limited time, all survival guide costs are eliminated, and you are able to teleport between nearby cities for a small fee, kupo!
        MARTIAL_MASTER_AS_AN_ADDED_BONUS_TO_YOUR                              = 11218,  -- Martial Master! As an added bonus to your Signet, combat skills will increase more rapidly! Your magic and automaton skills will be boosted, too!
        BLOOD_OF_THE_VAMPYR_SIGNETS_HAVE_BEEN_BOOSTED                         = 11219,  -- Blood of the Vampyr! Signets have been boosted with the abilities of Regeneration and Refresh!
        TREASURE_HOUND_WITH_SIGNET_IN_EFFECT_YOU_WILL                         = 11220,  -- Treasure Hound! With Signet in effect, you will now be able to sniff out more treasure and gil! Great riches surely await you, kupo!
        ARTISAN_S_ADVANTAGE_GOOD_NEWS_FOR_ASPIRING_ARTISANS                   = 11221,  -- Artisan's Advantage! Good news for aspiring artisans, kupo! When receiving advanced image support, the chance of your ingredients being lost in a failed synthesis attempt has been drastically reduced!
        MYRIAD_MYSTERY_BOXES_WHAT_S_THIS_KUPO_MYSTERIOUS                      = 11222,  -- Myriad Mystery Boxes! What's this, kupo? Mysterious boxes have been sighted all over the realm! What genius could have devised such commendable creations?
        DILATORY_DIGESTION_NOT_CONTENT_TO_BE_LEFT_BEHIND                      = 11223,  -- Dilatory Digestion! Not content to be left behind, brown magic slides back out for another go, kupo! Now you can be what you eat for twice as long and save on all those trips to your local merchant.
        BOUNDARY_BUSTER_TRUST_IN_SIGNET_AND_YOU_CAN                           = 11224,  -- Boundary Buster! Trust in Signet and you can never go wrong, kupo! It's time to take to the field and vanquish a veritable army of enemies, for any Conquest Points you receive will be duly doubled!
        BOUNTIFUL_BAZAAR_TRADE_ROUTES_ARE_BUSTLING_WITH_UNPRECEDENTED         = 11225,  -- Bountiful Bazaar! Trade routes are bustling with unprecedented traffic and peddlers' carts are overflowing with objects now that regional goods are available to merchants across the realm, kupo!
        SWIFT_SHOES_THIS_IS_JUST_THE_TICKET_FOR                               = 11226,  -- Swift Shoes! This is just the ticket for today's busy adventurer! For a limited time, provided that you're fully rested and healed, your legs will carry you with the speed of a chocobo!
        CRYSTAL_CABOODLE_SIGNET_IS_NOW_BETTER_THAN_EVER                       = 11227,  -- Crystal Caboodle! Signet is now better than ever! Collect crystals from beastmen-controlled areas...and maybe even clusters from other areas!
        BE_WARNED_THAT_OUR_MOOGLE_MAGIC_IS_CONCENTRATED                       = 11229,  -- Be warned that our moogle magic is concentrated around this altar. If you venture to far-off lands, the Super Kupowers will be unable to protect you...
        WHAT_WHAT_ABOUT_THE_PAST_YOU_SAY_OF                                   = 11230,  -- What? What about the past, you say? Of course the magic won't travel through time. What a strange question, kupo...
        BUT_NOT_AN_ALTOGETHER_POINTLESS_ONE_THE_POWERS                        = 11231,  -- But not an altogether pointless, one. The powers of thirtfy transit do seem to apply across the space-time continuum, kupo.
        THE_WHOLE_SYSTEM_IS_FILLED_WITH_MYSTERIES                             = 11232,  -- The whole system is filled with mysteries.
        OH_IT_S_YOU_IT_S_REALLY_YOU                                           = 11233,  -- Oh, it's you! It's really you! The brave adventurer who discovered one of our mog tablets!
        IT_S_A_PLEASURE_AN_HONOR_TO_MEET                                      = 11234,  -- It's a pleasure, an honor to meet you, kupo! We have a special prize to reward you for your efforts. If you'll just sign right here...
        SIGN_FOR_THE_MOOGLE_SURE_I_DON_T                                      = 11235,  -- Sign for the moogle? Sure. I don't think so.
        OH_THANK_YOU_MISTER_MISS_A_TRULY_HEROIC                               = 11236,  -- Oh, thank you, Mister/Miss]...%! A truly heroic name, kupo!
        AS_A_REWARD_FOR_YOUR_EFFORTS_PLEASE_HAVE                              = 11237,  -- As a reward for your efforts, please have this! Many thanks, and [safe travels/Happy Vana'versary], kupo!
        WHAT_YOU_WON_T_THAT_S_A_SHAME                                         = 11238,  -- What? You won't? That's a shame, kupo. I had a special prize here just for you, but without your signature, I'll just have to hold on to it...
        IF_YOU_CHANGE_YOUR_MIND_COME_BACK_QUICKLY                             = 11239,  -- If you change your mind, come back quickly. The mog tablets will be scattered to the wind again at any moment, kupo...
        F_TH_FTH_FON_U                                                        = 11240,  -- F<tH[ FtH[ %FoN;u
        FWOI_XQ_FO_AUK_FKOX_XO_FLOX_XO                                        = 11241,  -- FWOi[XQ Fo^#AuK FkOX^xO FlOX^xO
        FRV_BGN_FPV_NE_FX_KN_F_XFBXM                                          = 11242,  -- FRV%^bgn FpV%nE@ Fx#[kn F{XfBXM
        FUJO_H_F_T_O_FT_O_F                                                   = 11243,  -- FUJo[h F<T^o^ FT^o^ F^M%e,J
        FUU_F_T_GRN_F_OL_FNTB                                                 = 11244,  -- Fuu#< F#t@gRn F\Ol FNtB
        LJ_H_FE_K_FAEP_F9NWE                                                  = 11245,  -- %Lj#h Fe#K& FAep;F9nWE^
        FE_F_K_EXQ_F_AG_EXQ_F                                                 = 11246,  -- FE[ F^K%eXQ F%Ag%eXQ F<Aep;1
        TIMESTAMPF                                                            = 11248,  -- TimeStampF
        STEP_HJ_SUBSTEPF                                                      = 11249,  -- step%hj substepF
        A_B                                                                   = 11250,  -- A: B:
        ID_11255                                                              = 11255,  -- ====
        CODEF                                                                 = 11256,  -- codeF
        TIMEWORKF_TIMENOW_F_TIMELASTFSEC                                      = 11257,  -- TIMEWORKF TIMENOW F TIMELASTFSec.
        HI_THERE_I_M_YOUR_FRIENDLY_NEIGHBORHOOD_SMILE                         = 11258,  -- Hi there! I'm your friendly neighborhood smile sergeant! I'm in charge of running the [beginner/intermediate/advanced] level Smilebringer Boot Camp in this area.
        I_D_BE_THRILLED_TO_ANSWER_ANY_QUESTIONS                               = 11259,  -- I'd be thrilled to answer any questions you might have...and of course, sign you up, too! You'd like that, wouldn't you? Hmmm?
        WHAT_WILL_YOU_DO_UNDERTAKE_TRAINING_HEAR_AN                           = 11260,  -- What will you do? Undertake training. Hear an explanation. What's the qualifying time? What's the fastest time? Nothing.
        FANTASTIC_BUT_OH_IT_SEEMS_YOU_DON_T                                   = 11261,  -- Fantastic! But, oh...it seems you don't have %. Well, that's just too bad!
        IT_D_BE_MY_PLEASURE_HERE_GOES_NOTHING                                 = 11262,  -- It'd be my pleasure! Here goes nothing! Ahem! The Smilebringer Boot Camp was established for two purposes, the first being the ongoing training and conditioning of smilebringers. The second--and this is where you come in, yay!--is for us to scout hopefuls from the adventurer community to join our jovial ranks!
        THE_POPULATION_OF_VICIOUS_MONSTERS_HAS_GROWN_IN                       = 11263,  -- The population of vicious monsters has grown in recent years, you see. And because of this, more smilebringers were being--<gasp!>--injured in the line of duty than ever before.
        BUT_WE_WEREN_T_GOING_TO_TAKE_THAT                                     = 11264,  -- But we weren't going to take that sitting down, no siree. The day we smilebringers stop doing our job--that is, bringing smiles--is the day the world ends!
        WHATEVER_THE_PREDICAMENT_AND_NO_MATTER_THE_SIZE                       = 11265,  -- Whatever the predicament, and no matter the size of the ruszor-inflicted gash wound, we will--we must--pull through...for the sake of the children!
        WITH_THESE_HEART_WARMING_IDEALS_IN_MIND_THE                           = 11266,  -- With these heart-warming ideals in mind, the Smilebringer Boot Camp was established. Ta-da! Smilebringers graduating from this camp are better equipped to meet the ever-changing needs of these unstable times we live in.
        THE_RULES_ARE_AS_SIMPLE_AS_SUNSHINE_SMILEBRINGER                      = 11267,  -- The rules are as simple as sunshine. Smilebringer's honor! When I give you the word, run to each of the checkpoints we've set up in the area. Smile helpers are posted at each, so you can't miss them!
        TALK_TO_THE_SMILE_HELPERS_AND_THEY_LL                                 = 11268,  -- Talk to the smile helpers and they'll confirm your passage. The route you take is completely up to you--just be sure you don't miss any checkpoints. You got all that? Hmmm?
        I_LL_MARK_EACH_SMILE_HELPER_S_LOCATION                                = 11269,  -- I'll mark each smile helper's location on your map beforehand, so you don't need to worry about getting lost.
        ONCE_YOU_VE_FINISHED_VISITING_ALL_THE_CHECKPOINTS                     = 11270,  -- Once you've finished visiting all the checkpoints, you have to--you guessed it!--come back and report to me. It's okay, I won't bite!
        WHAT_I_WILL_DO_THOUGH_IS_TELL_YOU                                     = 11271,  -- What I will do, though, is tell you how quickly you completed the course. After all, to a smilebringer, speed is everything. Some folks run faster with a fell beast hot on their tail, but we smilebringers need no more than the thought of a child's laughter to spur us on! Zoom zoom!
        OH_AND_I_SHOULD_MENTION_THAT_AT_THIS                                  = 11272,  -- Oh, and I should mention that at this time of year, we're collecting donations in the form of a small fee to participate in the training. All proceeds go towards presents for the children during the Starlight Celebration. Thank you for your cooperation!
        ONE_MORE_THING_YOU_SHOULD_KNOW_IF_YOU                                 = 11273,  -- One more thing you should know. If you venture out of the area, the training will automatically be canceled. But I can trust you not to walk out on your favorite smile sergeant, right? Hmmm?
        SO_FAR_THE_FASTEST_TIME_IN_THIS_AREA                                  = 11274,  -- So far, the fastest time in this area is # minute[/s] # second[/s]. Wow! And the name of the greased lightning who set this record is %. Don't be forgetting that, you hear?
        WE_D_LIKE_ALL_PARTICIPANTS_TO_COMPLETE_THIS                           = 11275,  -- We'd like all participants to complete this area's course within # minute[/s] # second[/s]. A piece of cake for a strapping young wolf/vixen] like you, surely! And if you manage a time quicker than # minute[/s] # second[/s]...then you and I had better trade places! Oh, that would be so much fun, wouldn't it?
        AWWW_YOU_VE_MADE_THIS_SMILE_SERGEANT_VERY                             = 11276,  -- Awww... You've made this smile sergeant very sad... But I'll be glued to this spot, because I just know you'll be back to turn my frown upside down! Yes siree!
        AT_THIS_TIME_OF_YEAR_WE_RE_COLLECTING                                 = 11277,  -- At this time of year, we're collecting a donation of # gil from each participant. All proceeds go towards presents for the children. Oh, won't you think of the children? <Sniffle>...
        GIVE_TO_THE_CHILDREN_I_LIVE_TO_GIVE                                   = 11278,  -- Give to the children? I live to give! Charity begins at home.
        BUT_OF_COURSE_FIRST_I_LL_NEED_YOU                                     = 11279,  -- But of course! First, I'll need you to lend me your %... Oh, don't pout! I'll give it back as soon as I'm done, promise!
        YOU_LL_FIND_EACH_OF_THE_TEN_SMILE                                     = 11280,  -- You'll find each of the ten smile helpers by the points I've indicated. Don't forget to talk with every one of them or it won't count, okay?
        THERE_I_VE_MARKED_EACH_SMILE_HELPER_S                                 = 11281,  -- There! I've marked each smile helper's location for you. If you ever lose your bearings in the middle of a run, just open up your map and everything will be aaall right. Trust me! <Wink>
        SO_ARE_YOU_READY_STEADY_LEVEL_TRAINING_GO                             = 11282,  -- So, are you ready-steady? [Beginner/Intermediate/Advanced] level training...GO! Come on, pump those legs like there's no tomorrow!
        SINCE_THE_STARLIGHT_CELEBRATION_HAS_ENDED_WE_VE                       = 11283,  -- Since the Starlight Celebration has ended, we've had to make a few changes.
        BUT_THE_SMILEBRINGER_BOOT_CAMP_WILL_BE_AVAILABLE                      = 11284,  -- But the Smilebringer Boot Camp will be available for off-season conditioning the whole year round, so come back whenever you're in the mood. I'll be waiting for you!
        OH_YOU_RE_BACK_I_WAS_AFRAID_WE                                        = 11285,  -- Oh, you're back! I was afraid we'd lost you to some foul creature prowling the wilderness. Let's start from the top, shall we?
        OH_WHAT_RE_YOU_DOING_HERE_AREN_T                                      = 11286,  -- Oh, what're you doing here? Aren't you in the middle of a run right now? Couldn't stand to be parted from your favorite smile sergeant, maybe? Teehee!
        WHAT_WILL_YOU_DO_HEAR_AN_EXPLANATION_WHERE                            = 11287,  -- What will you do? Hear an explanation. Where're the smile helpers again? Cancel the training. Nothing.
        AWWW_THESE_RIVULETS_OF_TEARS_STREAMING_DOWN_MY                        = 11288,  -- Awww... These rivulets of tears streaming down my face... B-but it's okay... You have your own reasons for quitting, and I understand... <Sob>
        WELCOME_BACK_LET_S_CHECK_YOUR_TIME_SHALL                              = 11289,  -- Welcome back! Let's check your time, shall we? You cleared the course in # minute[/s] # second[/s].
        OH_MY_GODDESS_YOU_VE_SET_A_NEW                                        = 11290,  -- Oh my Goddess! You've set a new record for this area! Hooray! Somebody, break out the fireworks!
        YOU_VE_SUCCESSFULLY_QUALIFIED_YAY_HERE_S_A                            = 11291,  -- You've successfully qualified! Yay! Here's a little something to commemorate this marvelous achievement.
        YOU_OBTAIN_3                                                          = 11292,  -- You obtain %!
        AH_JUST_THE_KNOWLEDGE_THAT_THERE_RE_CAPABLE                           = 11293,  -- Ah, just the knowledge that there're capable adventurers like you around helps me sleep better at night. The children...they're in good hands... <Sob>
        YOU_DID_JUST_FINE_BUT_DON_T_BE                                        = 11294,  -- You did just fine, but don't be resting on those laurels, you hear? As we smilebringers say, there's always a bigger, brighter smile to be had!
        OH_NO_I_M_AFRAID_YOUR_TIME_FALLS                                      = 11295,  -- Oh no! I'm afraid your time falls short of qualification! As much as I want to give you a passing grade, headquarters wouldn't let me hear the end of it.
        OH_NO_PLEASE_DON_T_BE_MAD_BUT                                         = 11296,  -- Oh no! Please don't be mad, but...I forgot to record your time. I hope you'll find it in your heart to forgive this scatterbrain of a smile sergeant...
        IT_MIGHT_SURPRISE_YOU_TO_LEARN_THIS_BUT                               = 11297,  -- It might surprise you to learn this, but even the toughest--grrrrrr!--and roughest of us smilebringers need rest and relaxation. Oh, wipe that grin off your face! I knew you wouldn't believe me!
        AAANYWAY_WHAT_I_MEANT_TO_SAY_IS_WORK                                  = 11298,  -- Aaanyway! What I meant to say is, work hard, play hard is our motto, and it applies to boot camp participants, too. After you complete a run with a qualifying time--yay!--you're required to rest up until the next day (Vana'diel time).
        AWWW_SEEING_THE_WAY_YOU_RE_SIMPLY_BURSTING                            = 11299,  -- Awww, seeing the way you're simply bursting with enthusiasm makes me want to cry tears of joy. But you have to be cruel to be kind. No more training until tomorrow, young man/lady]! No siree!
        DEBUG_MESSAGES                                                        = 11300,  -- Debug Messages.
        ALL_CHECKPOINTS_SWITCHED_ON_PARTICIPATION_XMAS_OFF                    = 11301,  -- All checkpoints switched ON. Participation: # Xmas: # OFF: #
        ELAPSED_TIME_MIN_AND_SEC                                              = 11302,  -- Elapsed time: # min and # sec.
        CHANGE_EVENT_MODE_STARLIGHT_CELEBRATION_OFF_SEASON_EVENT              = 11303,  -- Change event mode. Starlight Celebration. Off-season. Event off.
        CHECKPOINT_CLEARED_ELAPSED_TIME_MINUTE_SECOND                         = 11304,  -- Checkpoint ## cleared! Elapsed time: # minute[/s] # second[/s]
        CHECKPOINT_CLEARED_YOU_GAIN_THE_EFFECT_OF_FLEE                        = 11305,  -- Checkpoint ## cleared! You gain the effect of Flee. Elapsed time: # minute[/s] # second[/s]
        YOU_HAVE_ALREADY_CLEARED_THIS_CHECKPOINT_ELAPSED_TIME                 = 11306,  -- You have already cleared this checkpoint. Elapsed time: # minute[/s] # second[/s]
        ELAPSED_TIME_MINUTE_SECOND                                            = 11307,  -- Elapsed time: # minute[/s] # second[/s]
        ALL_CHECKPOINTS_CLEARED_PLEASE_REPORT_BACK_TO_THE                     = 11308,  -- All checkpoints cleared! Please report back to the smile sergeant in charge.
        TARGET_OUT_OF_RANGE_2                                                 = 11309,  -- Target out of range.
        THIS_IS_A_CHECKPOINTARU_FOR_THE_SMILEBRINGER_BOOT                     = 11310,  -- This is a checkpointaru for the Smilebringer Boot Camp. To learny-wearn more, please speak with the smile sergeant posted by the [town entrance/telepointaru].
        YOU_OBTAIN_4                                                          = 11311,  -- You obtain % !
        THE_QUIVERS_EVER_SO_SLIGHTLY_BUT_EMITS_NO                             = 11312,  -- The % quivers ever so slightly, but emits no light. There seem to be no monsters in the area.
        THE_QUIVERS_EVER_SO_SLIGHTLY_AND_EMITS_A                              = 11313,  -- The % quivers ever so slightly and emits a faint light. There seem to be no monsters in the immediate vicinity.
        THE_RESONATES_SENDING_A_RADIANT_BEAM_OF_LIGHT                         = 11314,  -- The % resonates [feebly/softly/solidly/strongly/very strongly/furiously], sending a radiant beam of light lancing towards a spot roughly # [yalm/yalms] [east/southeast/south/southwest/west/northwest/north/northeast] of here.
        A_MONSTER_MATERIALIZES_OUT_OF_NOWHERE                                 = 11315,  -- A monster materializes out of nowhere!
        THE_MONSTER_FADES_BEFORE_YOUR_EYES_A_LOOK_2                           = 11316,  -- The monster fades before your eyes, a look of disappointment on its face.
        THE_TAKES_ON_A_SLIGHTLY_DEEPER_HUE_AND                                = 11317,  -- The % takes on a slightly deeper hue and becomes %!
        THE_TAKES_ON_A_DEEPER_RICHER_HUE_AND                                  = 11318,  -- The % takes on a deeper, richer hue and becomes %!
        THE_SHATTERS_INTO_TINY_FRAGMENTS                                      = 11319,  -- The % shatters into tiny fragments.
        OBTAINED_KEY_ITEM_2                                                   = 11320,  -- Obtained key item: %!
        THE_MONSTER_FADES_BEFORE_YOUR_EYES_A_LOOK_3                           = 11321,  -- The monster fades before your eyes, a look of disappointment on its face.
        YOU_HAVE_LOST_SIGHT_OF_THE_MONSTER_AND                                = 11322,  -- You have lost sight of the monster and can no longer sense its presence.
        YOU_HAVE_WANDERED_TOO_FAR_FROM_THE_MONSTER                            = 11323,  -- You have wandered too far from the monster and can no longer sense its presence.
        DEBUG_COMMENCE_SEARCH                                                 = 11324,  -- DEBUG: Commence Search.
        DEBUG_END_SEARCH                                                      = 11325,  -- DEBUG: End Search.
        DEBUG_NO_MONSTERS_HAVE_SPAWNED                                        = 11326,  -- DEBUG: No monsters have spawned.
        DEBUG_A_MONSTER_HAS_SPAWNED_BUT_IS_TOO                                = 11327,  -- DEBUG: A monster has spawned, but is too far away.
        DEBUGFTYPE_DEBUGFDIRECTION_DEBUG_DEBUGFNUMBER                         = 11328,  -- DEBUGFType: [Small Fry/NM/Shadow HNM/Shadow SHNM/True HNM/True SHNM] DEBUGFDirection: [East/Southeast/South/Southwest/West/Northwest/North/Northeast] DEBUG%DEBUGFNumber: #
        DEBUG_NO_CLAIMED                                                      = 11329,  -- DEBUG: No. # claimed!
        DEBUG_NO_HAS_SPAWNED                                                  = 11330,  -- DEBUG: No. # has spawned.
        DEBUGFNO_IS_HIDDEN                                                    = 11331,  -- DEBUGFNo. # is hidden.
        DEBUGFJADE_OBTAINED                                                   = 11332,  -- DEBUGFJade obtained!
        DEBUGFJADE_DISCARDED                                                  = 11333,  -- DEBUGFJade discarded!
        DEBUGFNM_JADE_OBTAINED                                                = 11334,  -- DEBUGFNM Jade obtained!
        DEBUGFNM_JADE_DISCARDED                                               = 11335,  -- DEBUGFNM Jade discarded!
        DEBUGFHNM_JADE_OBTAINED                                               = 11336,  -- DEBUGFHNM Jade obtained!
        DEBUGFHNM_JADE_DISCARDED                                              = 11337,  -- DEBUGFHNM Jade discarded!
        DEBUGFHNM_JADE_2_OBTAINED                                             = 11338,  -- DEBUGFHNM Jade 2 obtained!
        DEBUGFHNM_JADE_2_DISCARDED                                            = 11339,  -- DEBUGFHNM Jade 2 discarded!
        GRRR_DAMN_THIS_CHAFING_SENSATION                                      = 11340,  -- Grrr! Damn this chafing sensation!
        HM_WHY_TH_THAT_STONE_YOU_BEAR                                         = 11341,  -- Hm? Why, th-that stone you bear...
        AM_I_CORRECT_IN_ASSUMING_THAT_YOU_RE                                  = 11342,  -- Am I correct in assuming that you're %?
        ARE_YOU_THE_ONE_AND_ONLY                                              = 11343,  -- Are you %? The one and only! ...
        TRULY                                                                 = 11344,  -- Truly!?
        MY_NAME_IS_RAGEMONT_AND_I_WAS_TOLD                                    = 11345,  -- My name is Ragemont, and I was told that you might show--
        AAARGH_C_CONFOUND_IT                                                  = 11346,  -- Aaargh! C-confound it!
        I_MUST_ASK_YOU_TO_DISREGARD_THESE_ABRUPT                              = 11347,  -- I must ask you to disregard these abrupt outbursts. This pain is an inseparable part of inter-dimensional travel.
        THOUGH_I_M_MADE_TO_UNDERSTAND_THAT_PEOPLE                             = 11348,  -- Though I'm made to understand that people of this world do not experience it.
        OH_YOU_VE_NOT_BEEN_INFORMED_THEN_IT                                   = 11349,  -- Oh, you've not been informed? Then it would be my pleasure to explain.
        IN_CROSSING_OVER_TO_THIS_WORLD_RESIDENTS_OF                           = 11350,  -- In crossing over to this world, residents of Abyssea suffer from a phenomenon wherein their strength is halved. Devivification, 'tis called, though the exact science of it remains beyond our fathoming.
        CURIOUSLY_THE_REVERSE_IS_KNOWN_TO_OCCUR_WHEN                          = 11351,  -- Curiously, the reverse is known to occur when people of your world cross over to ours.
        AND_IT_IS_EXACTLY_FOR_THIS_REASON_THAT                                = 11352,  -- And it is exactly for this reason that you're so important in our struggle. Only with the help of your enhanced powers could we hope to subdue the Abyssean menace and set the world to rights.
        AH_BUT_I_DO_RAMBLE_SHOULD_YOU_HAVE                                    = 11353,  -- Ah, but I do ramble. Should you have any questions, my knowledge is at your disposal.
        WHAT_WILL_YOU_ASK_ABOUT_DEVIVIFICATION_THE_REVERSE                    = 11354,  -- What will you ask about? Devivification. The reverse effect. Nothing in particular.
        AS_I_HAD_MENTIONED_PRIOR_THE_JOURNEY_HERE                             = 11355,  -- As I had mentioned prior, the journey here from Abyssea causes our strength to become halved.
        IN_PRACTICE_IT_S_AS_IF_WE_RE                                          = 11356,  -- In practice, it's as if we're in a constant state of weakness. Adding insult to injury, an unbearable chafing sensation assails us without warning.
        SOUNDS_BOTHERSOME_DOESN_T_IT_YET_WE_DO                                = 11357,  -- Sounds bothersome, doesn't it? Yet we do what we must. The pain that ensues after each crossing compares not to the eternal death of our world.
        NOT_EVERYONE_IS_POSSESSED_OF_THE_ABILITY_TO                           = 11358,  -- Not everyone is possessed of the ability to traverse dimensions, mind you. How it's decided that one child will be born with the gift but not another, mortals such as ourselves may never learn the truth of it.
        NO_REWARDS_FOR_GUESSING_CORRECTLY_BUT_THE_REVERSE                     = 11359,  -- No rewards for guessing correctly, but the reverse effect is referred to as vivification. The process can be described in terms of plants.
        IMAGINE_YOURSELF_AS_A_SAPLING_AND_ABYSSEA_A                           = 11360,  -- Imagine yourself as a sapling, and Abyssea a pot many times larger than you're accustomed to, filled with humus-rich soil. As the sapling thrives in such an auspicious environment, blooming forth with flowers beauteous and many, so too will your strength and abilities flourish in Abyssea.
        ONLY_THOSE_OF_YOUR_WORLD_WITH_THE_ABILITY                             = 11361,  -- Only those of your world with the ability to cross over to ours may attain the strength that is needed to battle the Abyssean hordes. Do you understand now why your aid is so valuable to us?
        I_SEE                                                                 = 11362,  -- I see...
        AH_YES_WITH_REGARDS_TO_THE                                            = 11363,  -- Ah, yes. With regards to the %...
        BEYOND_THIS_CAVERNOUS_MAW_LIES_ANOTHER_LA_THEINE                      = 11364,  -- Beyond this cavernous maw lies another La Theine Plateau, though you will find little resemblance beyond the name.
        I_MUST_SAY_IT_EASES_THE_HEART_TO                                      = 11365,  -- I must say, it eases the heart to stand beneath a sky that isn't a constant and bloody reminder of encroaching death...
        AH_ONCE_AGAIN_I_MUST_APOLOGIZE_I_AM                                   = 11366,  -- Ah, once again I must apologize. I am wont to become lost in such sentimental thoughts on occasion.
        THE_LA_THEINE_OF_ABYSSEA_IS_NO_LONGER                                 = 11367,  -- The La Theine of Abyssea is no longer the picturesque, tranquil plateau we stand upon. Seeing its former beauty restored is my fervent desire.
        THERE_EXISTS_AN_ABYSSEAN_MONSTER_THAT_HAS_BEEN                        = 11368,  -- There exists an Abyssean monster that has been a great scourge to us--a Gigas of fearsome stature and savagery who dons a golden helm.
        DEFEATING_THIS_CREATURE_WOULD_BE_TANTAMOUNT_TO_LAYING                 = 11369,  -- Defeating this creature would be tantamount to laying the foundation stones for our dreams of peace.
        YET_A_FOUNDATION_REQUIRES_MANY_A_HEAVY_STONE                          = 11370,  -- Yet a foundation requires many a heavy stone to be laid if a sturdy tower is to be built. More often than not, though, it feels as if we go about constructing this tower of dreams bereft of an architectural plan.
        AND_SO_WE_COME_TO_THIS_WORLD_SEEKING                                  = 11371,  -- And so we come to this world, seeking the aid of brave souls such as you. By ourselves, we stand not a sliver of a chance against the Abyssean hordes.
        EGADS_I_VE_LOST_TRACK_OF_TIME_YET                                     = 11372,  -- Egads, I've lost track of time yet again. I must away before I'm missed. Before I take my leave, however, I would offer you a few words of advice.
        YOU_ARE_NOT_ALONE_THERE_ARE_OTHERS_OF                                 = 11373,  -- You are not alone. There are others of this world who have been blessed with the same gift as you.
        AND_DO_TREAD_WARILY_WHEN_FIRST_YOU_SET                                = 11374,  -- And do tread warily when first you set foot on Abyssean soil. For though our worlds may bear some resemblance, the difference may well determine life and death.
        TIL_WE_MEET_AGAIN_FARE_YOU_WELL                                       = 11375,  -- 'Til we meet again...fare you well!
        ID_11376                                                              = 11376,  -- ...
        THE_STRANGER_STARES_INTENTLY_AT                                       = 11377,  -- The stranger stares intently at %.
        YOU_MUST_BE                                                           = 11378,  -- You must be %.
        THE_NAME_S_OAK_KNOTTY_OAK                                             = 11379,  -- The name's Oak. Knotty Oak.
        I_KNOW_YOU_RE_EXPECTING_TO_SEE_RAGEMONT                               = 11380,  -- I know you're expecting to see Ragemont, but I'm afraid he won't be coming by anymore.
        HE_SAVED_MY_LIFE_IN_BATTLE_BUT_PAID                                   = 11381,  -- He saved my life in battle, but paid for it with his own. For this gift, I intend to carry on his legacy.
        I_VE_HEARD_OF_YOUR_EXPLOITS_IN_OUR                                    = 11382,  -- I've heard of your exploits in our world, %. You've proven yourself a true friend to the cause. Thank you.
        NOW_THIS_ISN_T_MUCH_BUT_I_THINK                                       = 11383,  -- Now this isn't much, but I think you'll find it useful.
        FOREIGN_DIMENSIONERS_ARE_KNOWN_TO_HAVE_AN_AFFINITY                    = 11384,  -- %. Foreign-dimensioners are known to have an affinity for it.
        WHETHER_WE_VE_GOTTEN_CLOSER_TO_FULFILLING_RAGEMONT                    = 11385,  -- Whether we've gotten closer to fulfilling Ragemont's wish, no one can say.
        BUT_I_BELIEVE_THAT_HIS_MEETING_WITH_YOU                               = 11386,  -- But I believe that his meeting with you will count for something.
        SORRY_BUT_I_WAS_NEVER_GOOD_WITH_WORDS                                 = 11387,  -- Sorry, but I was never good with words.
        THIS_IS_ONE_PEACEFUL_WORLD_YOU_GOT_HERE                               = 11388,  -- This is one peaceful world you got here. It's good to see exactly what it is we're fighting to reclaim...
        ARRRG_FANCY_SEEIN_SOMEONE_IN_THESE_PARTS                              = 11389,  -- Arrrg. Fancy seein' someone in these parts.
        HMM_WOULD_YE_HAPPEN_T_BE_BY_ANY                                       = 11390,  -- Hmm? Would ye happen t' be %, by any chance?
        PASSIN_STRANGE_THOUGHT_I_D_RECOGNIZE_YE_ON                            = 11391,  -- Passin' strange... Thought I'd recognize ye on sight, but perhaps age has clouded me eye. Now that we finally meet, though, I do sense somethin' diff'rent about ye.
        YE_RE_WONDERIN_HOW_I_DISCERN_SUCH_THINGS                              = 11392,  -- Ye're wonderin' how I discern such things, aye? Well, a man don't live t' me age without learnin' a trick or two...although experience don't account fer all, t' be fair.
        WHAT_S_THE_MATTER_YE_LOOK_LIKE_YE                                     = 11393,  -- What's the matter? Ye look like ye've just been t' Davy Jones's locker an' back.
        LET_ME_TAKE_A_WILD_STAB_YE_RE                                         = 11394,  -- Let me take a wild stab: ye're acquainted with the me o' this world. Aye, ye've got an exprrression that says I know what ye know, matey.
        HMM_CURSE_ME_FER_A_FOOL_FATHER_BUT                                    = 11395,  -- Hmm... Curse me fer a fool father, but that sparkle o' determination in yer eyes puts me in mind o' me dear daughter.
        IT_SEEMS_I_VE_GONE_AN_TAKEN_LEAVE                                     = 11396,  -- It seems I've gone an' taken leave o' me mannerrrs, like folk o' me trade are wont t' do.
        THANK_YE_FER_MAKIN_THE_JOURNEY_HERE_NAME                              = 11397,  -- Thank ye fer makin' the journey here. Name's Gilgamesh. I be in the business o' liberrratin' cargo from those as don't need it an' givin' it to those who do--usually meself an' me boys. Call it philanthropy. Or call it piracy if ye like.
        NOTHIN_COMPARES_T_GLIDIN_UPON_THE_WAVES_ON                            = 11398,  -- Nothin' compares t' glidin' upon the waves on the high seas, feelin' the caress o' the wind as she fills yer sails with her sweet brrreath. Aye, the unfettered life o' a pirate be the life fer me.
        BUT_ALL_O_THAT_AN_MORE_WAS_TAKEN                                      = 11399,  -- But all o' that an' more was taken away when me world Abyssea took grievously ill.
        AYE_EVERYTHIN_WE_KNEW_CRUMBLED_AWAY_LIKE_OL                           = 11400,  -- Aye, everythin' we knew crumbled away like ol' hard tack what even the ship rats won't touch. An' it got me t' thinkin'. Piratin' be tough when t'ain't no more merchants what needs piratin'. So I volunteered me services t' the resistance effort, wantin' to do me part fer mankind, ye see. I be an officer, in fact...
        THAT_BE_WHEN_THE_RUMORS_O_YE_FIRST                                    = 11401,  -- That be when the rumors o' ye first reached me, %. The lil' mistress had heard o' ye, too, an' assigned me the task o' measurrrin' yer suitability. So here I be.
        ASK_ABOUT_RUMORS_THE_LIL_MISTRESS_SUITABILITY                         = 11402,  -- Ask about... Rumors. The lil' mistress. Suitability.
        YER_RIGHT_AUDACIOUS_FEATS_IN_OUR_RAVAGED_WORLD                        = 11403,  -- Yer right audacious feats in our ravaged world've earned ye considerable renown, matey. Thanks t' yer exploits, survivors across areas've learned o' each other's existence. Unity o' purpose is startin' t' be seen again.
        TRUTH_BE_TOLD_STUBBORN_AS_WE_WERE_AT                                  = 11404,  -- Truth be told, stubborn as we were, at first it was difficult fer us t' admit that we needed outside help t' survive.
        BUT_PRRRIDE_OFFERS_SMALL_COMFORT_WHEN_LOVED_ONES                      = 11405,  -- But prrride offers small comfort when loved ones are dyin' in yer arms. So we swallowed it, in order t' begin our arduous journey towards salvation.
        A_LONG_AN_UNCERTAIN_ROAD_LIES_AHEAD_T                                 = 11406,  -- A long an' uncertain road lies ahead, t' be sure, but with the aid o' brave souls such as ye, we'll get t' our destination yet.
        YE_BE_CURIOUS_ABOUT_WHO_I_MEANT_BY                                    = 11407,  -- Ye be curious about who I meant by the lil' mistress? Sorry, matey, but that information ain't mine t' sharrre. Arrrg.
        NO_NEED_T_FRET_THOUGH_CAUSE_I_VE                                      = 11408,  -- No need t' fret, though, 'cause I've got a feelin' ye'll get t' meet the lady soon enough.
        TAKIN_ANOTHER_WILD_STAB_MIGHT_BE_YE_RE                                = 11409,  -- Takin' another wild stab, might be ye're already acquainted with her in this worrrld, much like ye know me. Though this be simple speculation, mind ye.
        T_SPARE_YE_THE_SUSPENSE_YE_VE_PASSED                                  = 11410,  -- T' spare ye the suspense, ye've passed with flyin' colors, matey.
        NAVIGATIN_ABYSSEA_LIKE_IT_WERE_YER_OWN_LIL                            = 11411,  -- Navigatin' Abyssea like it were yer own lil' pond, smitin' beasties that'd shame all the horrors o' the sea like they're no more'n guppies--takes uncommon courage an' a healthy dose o' foolhardiness.
        AYE_YE_BE_A_REGULAR_SWASHBUCKLER_I_RECKON                             = 11412,  -- Aye, ye be a regular swashbuckler, I reckon.
        THERE_BE_ONE_AMONG_US_COME_FROM_THE                                   = 11413,  -- There be one among us come from the old Federation, an eccentric but likeable fellow. His field o' interest be the boundary between worlds, which he claims is gettin' t' be about as stable as an ol' sea dog w' two peg legs, an' it don't get much more unstable 'n that, matey. Ye ever heard o' such a thing?
        MULTIPLE_DIMENSIONS_EXIST_IN_A_SINGLE_WORLD_YE                        = 11414,  -- Multiple dimensions exist in a single world, ye see, places similar yet different. Knowin' this, the notion that there be things the eye can't see becomes easier t' swallow, aye? Kinda like takin' a nice, long swig from me tankarrrd t' wash down the foul herbal remedy fer me heartburn. But that be a tale fer another day.
        GETTIN_BACK_ON_TOPIC_THE_BOUNDARY_BE_GROWIN                           = 11415,  -- Gettin' back on topic, the boundary be growin' unstable, ever since the dimensions synchronized...or so I be told. Can ye imagine such a phenomenon? Are ye still even followin' what I'm sayin'? 'Cause, blimey, even I ain't sure I follow meself sometimes.
        I_DON_T_CLAIM_FULL_UNDERSTANDIN_O_ALL                                 = 11416,  -- I don't claim full understandin' o' all this, but it don't take no atma infusionist t' see there be a problem. Aye, even a boorish pirate such as meself can tell when all hell's brrroken loose.
        WHAT_S_ANY_O_THIS_GOT_T_DO                                            = 11417,  -- What's any o' this got t' do with yer suitability, ye ask? Why, everything, matey! Our world's been fair turned into a disaster zone, an' we need mettlesome folk who won't get all squeamish when confrontin' the mess. And by me measurin' stick, ye surpass that requirement by a nautical malm.
        KEEP_IN_MIND_THOUGH_THAT_IT_S_ALL                                     = 11418,  -- Keep in mind, though, that it's all over if ye die. Ye've got just the one life, so careful what ye do with it. These words must seem hollow, comin' from the selfsame bastarrrd who's askin' ye t' dive headlong into danger. But we've already lost enough things we care fer. The gods be damned if we lose any more.
        ARRRG_BUT_I_RAMBLE_I_FEAR_ME_MIND                                     = 11419,  -- Arrrg, but I ramble. I fear me mind's become much given t' wanderlust in old age. Resistin' the urge t' go off on a tangent or state the bleedin' obvious be about as hard as resistin' the call o' drink. Ye'll have t' bear with me.
        DURIN_ME_PIRATIN_DAYS_I_SAW_MANY_A                                    = 11420,  -- Durin' me piratin' days, I saw many a thing n' more. Arrrg, there be nothin' left in the world that could surprise this sea dog, I'd often boast.
        BUT_THEN_THE_EARTH_CRUMBLED_AN_THE_SKIES                              = 11421,  -- But then the earth crumbled an' the skies turned a bloody red, leavin' this brrraggart as dumbstruck an' clueless as a bleedin' lan'lubber gawpin' o'er an anchor hitch.
        SO_FER_ALL_ME_YAPPIN_I_VE_REALLY                                      = 11422,  -- So fer all me yappin', I've really got nothin' useful t' share with ye. At least not fer the time bein'. The lil' mistress, however, she be a veritable treasure trove o' knowledge, aye.
        WHY_DO_I_KNOW_SO_LITTLE_YE_ASK                                        = 11423,  -- Why do I know so little, ye ask? Why, that be a question o' readiness t' face the truth o' things, matey. Fer me, it seems the time's yet t' come.
        EARLIER_I_TOLD_YE_O_ME_INVOLVEMENT_WITH                               = 11424,  -- Earlier, I told ye o' me involvement with the resistance. But truth be told, it's all this retired pirate can do t' keep himself an' those around him alive. All o' us have things we're bound t' prrrotect, after all.
        IT_SHAMES_ME_T_NO_END_HAVIN_T                                         = 11425,  -- It shames me t' no end, havin' t' rely on the kindness o' selfless folk like yerself...but there be no help fer it.
        FACT_IS_YER_AID_WILL_BE_O_FAR                                         = 11426,  -- Fact is, yer aid will be o' far greater worth t' the lil' mistress than what me folk an' I could ever muster up.
        BUT_DON_T_BE_PRESUMIN_THAT_WE_MEAN                                    = 11427,  -- But don't be presumin' that we mean t' sit idly by, scratchin' our bum cheeks. Yer courageous exploits have instilled much needed morale within the survivors, an' they stand rrready t' fight again.
        THE_REAL_BATTLE_STARTS_FROM_HERE_AN_MANKIND                           = 11428,  -- The real battle starts from here, an' mankind ain't goin' down without a struggle, this I promise ye. Whatever bloodlust drives those vile creatures, we'll match it an' more with our will t' live.
        SHIVER_ME_TIMBERS_WOULD_YE_LOOK_AT_THE                                = 11429,  -- Shiver me timbers, would ye look at the time? I must be headin' back before I'm missed. Be a good lad/lass] an' pass me regards t' Joachim, would ye?
        I_LOOK_FORWARD_T_OUR_NEXT_MEETIN_I                                    = 11430,  -- I look forward t' our next meetin', %. I promise t' cork up me rrramblin' then. Arrrg.
        AHOY_THERE_MATEY_HOPE_I_DIDN_T_MAKE                                   = 11431,  -- Ahoy there, matey. Hope I didn't make ye wait overlong.
        TRUTH_BE_TOLD_I_DIDN_T_IMAGINE_WE                                     = 11432,  -- Truth be told, I didn't imagine we'd need t' meet again so soon.
        I_BRING_GRIM_NEWS_URGENT_TIDINGS_THAT_WANTS                           = 11433,  -- I bring grim news, %. Urgent tidings that wants fer tellin'.
        AFTER_REGAININ_CONTACT_WITH_THE_SURVIVORRRS_WE_GOT                    = 11434,  -- After regainin' contact with the survivorrrs, we got them conductin' thorough investigations in their respective locales.
        WITH_YER_KEEN_EYES_YE_VE_NO_DOUBT                                     = 11435,  -- With yer keen eyes, ye've no doubt already noticed the disfigured Abyssean landscape. At first we all assumed the earthquake t' be the culprit, the one that shook the earth that fateful day.
        BUT_AS_WE_JUST_DISCOVERED_THAT_BE_NOT                                 = 11436,  -- But as we just discovered, that be not the case. The root o' the problem runs far deeper than all imaginin'.
        I_DIDN_T_MENTION_IT_AT_OUR_LAST                                       = 11437,  -- I didn't mention it at our last meetin', but once I had the pleasure o' workin' with a bunch fondly referred t' as the Champions o' Abyssea.
        A_GOOD_HEARTED_LOT_THEY_WERE_ALWAYS_TIRELESSLY                        = 11438,  -- A good-hearted lot they were, always tirelessly scurrin' about, gettin' things done behind the scenes.
        ONCE_I_ASKED_THEM_WHAT_BE_THEIR_DRRRIVIN                              = 11439,  -- Once, I asked them what be their drrrivin' force. An' how do ye imagine they responded? With naught but a mischievous grin! Hah! A right mysterious bunch they were, as many an' unique as the fishes in the sea.
        SO_UH_NOT_RINGIN_ANY_BELLS_WELL_SMALL                                 = 11440,  -- So...uh...not ringin' any bells? Well, small wonder, what with me penchant fer incoherent bletherin'. Let me put it in a way right-minded folk'll understand: in yer world Vana'diel, the Champions o' Abyssea be ye adventurers. Aye, ye included, matey.
        DURIN_YER_TIME_IN_ABYSSEA_YE_VE_SURELY                                = 11441,  -- Durin' yer time in Abyssea, ye've surely met folk who also exist in yer world. However, ye've yet t' meet yerself. Have ye ever given thought t' why that is?
        THE_ANSWER_BE_REMARRRKABLY_SIMPLE_YE_DON_T                            = 11442,  -- The answer be remarrrkably simple. Ye don't exist in that world no more. The reason be not known t' me, I'm afeared. One day, we simply lost contact with ye.
        ANY_ONE_O_A_THOUSAND_THINGS_COULD_VE                                  = 11443,  -- Any one o' a thousand things could've happened t' cause yer disappearance, matey. An' the possibilities be multiplied when I be in me cups, arrrg.
        BUT_NO_USE_DWELLIN_ON_IT_RIGHT_NOW                                    = 11444,  -- But no use dwellin' on it right now. It's high time we be gettin' back t' the topic o' the investigation.
        ONE_CHANGE_O_PARTICULAR_NOTE_WAS_REPORTED_THERE                       = 11445,  -- One change o' particular note was reported: there be places where the land's breakin' down in a lattice pattern.
        THIS_PHENOMENON_BE_HAPPENIN_THROUGHOUT_THE_REALM_MATEY                = 11446,  -- This phenomenon be happenin' throughout the realm, matey, on a level so subtle it'd escape the notice o' untrrrained eyes.
        THE_SKIES_TURNIN_A_BLOODY_RED_ENDLESS_SWARMS                          = 11447,  -- The skies turnin' a bloody red... Endless swarms o' beasties crawlin' out o' dark crevasses... The world's undergone changes never b'fore seen by mankind.
        YET_I_CAN_T_HELP_BUT_FEEL_THAT                                        = 11448,  -- Yet...I can't help but feel that these be piddlin' lil' things compared t' what's on the horizon.
        MERE_DROPLETS_FROM_THE_KEG_THAT_S_ABOUT                               = 11449,  -- Mere droplets from the keg that's about t' be upturned over our heads. The wind b'fore the squall. A ramblin', disjointed preamble b'fore the--
        AHEM_WELL_I_THINK_YE_GET_THE_POINT                                    = 11450,  -- Ahem! Well, I think ye get the point. So, this trepidation be eatin' away at me insides, matey, an' I can't stand it no more.
        I_VE_RRRESOLVED_T_SEEK_THE_ANSWERS_FROM                               = 11451,  -- I've rrresolved t' seek the answers from the lil' mistress--ask her all she knows about what's befallen our world, an' what horrors are still t' come.
        WHETHER_I_BE_READY_T_DEAL_WITH_THE                                    = 11452,  -- Whether I be ready t' deal with the truth, I can't say.
        BUT_THE_FATE_O_THE_WORLD_WON_T                                        = 11453,  -- But the fate o' the world won't wait on the readiness o' one man. Fer better or fer worse, I must go an' do this thing.
        ARRRG_LOOKS_LIKE_ME_CURSED_MOUTH_FOUND_A                              = 11454,  -- Arrrg, looks like me cursed mouth found a will o' its own once again. I sure as hell hope I haven't put ye off future meetings between us, matey.
        FER_NOW_FARE_YE_WELL                                                  = 11455,  -- Fer now, fare ye well.
        YOU_ARE_TOO_FAR_AWAY_TO_PARTICIPATE_IN                                = 11456,  -- You are too far away to participate in the Voidwatch operation.
        YOU_ARE_CURRENTLY_ENGAGED_ELSEWHERE_AND_CANNOT_PARTICIPATE            = 11457,  -- You are currently engaged elsewhere and cannot participate in the Voidwatch operation.
        YOU_ARE_UNCONSCIOUS_AND_CANNOT_PARTICIPATE_IN_THE                     = 11458,  -- You are unconscious and cannot participate in the Voidwatch operation.
        YOU_DO_NOT_FULFILL_THE_REQUIREMENTS_TO_PARTICIPATE                    = 11459,  -- You do not fulfill the requirements to participate in the Voidwatch operation.
        GAINS_CLEARANCE_TO_PARTICIPATE_IN_THE_VOIDWATCH_OPERATION             = 11460,  -- % gains clearance to participate in the Voidwatch operation. One % expended.
        GAINS_CLEARANCE_TO_PARTICIPATE_IN_THE_VOIDWATCH_OPERATION_2           = 11461,  -- % gains clearance to participate in the Voidwatch operation. % not expended. (Spoils will be subject to limits.)
        GAINS_CLEARANCE_TO_PARTICIPATE_IN_THE_VOIDWATCH_OPERATION_3           = 11462,  -- % gains clearance to participate in the Voidwatch operation. Unused % carried over.
        YOU_HAVE_VENTURED_TOO_FAR_FROM_THE_FIELD_3                            = 11463,  -- You have ventured too far from the field of battle. You will be automatically relieved of Voidwatcher status if you do not return.
        YOU_HAVE_VENTURED_TOO_FAR_FROM_THE_FIELD_4                            = 11464,  -- You have ventured too far from the field of battle. Voidwatcher status revoked.
