        YOU_HAVE_EARTH_TIME_TO_COMPLETE_THE_BATTLE_2                          = 11466,  -- You have # [minute/minutes] (Earth time) to complete the battle.
        YOU_HAVE_EARTH_TIME_REMAINING_TO_COMPLETE_THE_2                       = 11467,  -- You have # [minute/minutes] (Earth time) remaining to complete the battle.
        YOU_HAVE_ONLY_EARTH_TIME_REMAINING_2                                  = 11468,  -- You have only # [second/seconds] (Earth time) remaining.
        YOUR_TIME_FOR_THIS_BATTLE_IS_UP                                       = 11469,  -- Your time for this battle is up...
        THE_MONSTER_FADES_BEFORE_YOUR_EYES_A_LOOK_4                           = 11470,  -- The monster fades before your eyes, a look of disappointment on its face.
        TEMPORARY_ITEM_IS_AVAILABLE_FOR_USE                                   = 11471,  -- Temporary item: % is available for use!
        ALL_TEMPORARY_ITEMS_ARE_RECHARGED                                     = 11472,  -- All temporary items are recharged!
        YOU_FEEL_A_MYSTERIOUS_ENERGY_SEEPING_FORTH_FROM                       = 11473,  -- You feel a mysterious energy seeping forth from an unknown source...
        THE_RESONATES_WITH_THE_YOU_MAY_COMMENCE_THE                           = 11474,  -- The % resonates with the %. You may commence the Voidwatch operation at will.
        A_VOIDWATCH_OPERATION_COULD_BE_INITIATED_IF_ONLY                      = 11475,  -- A Voidwatch operation could be initiated if only you had % and %...
        HOWEVER_YOUR_PRESENCE_DOES_NOT_SEEM_TO_ELICIT                         = 11476,  -- However, your presence does not seem to elicit a reaction.
        WHAT_WILL_YOU_DO_NOTHING_INITIATE_VOIDWATCH_OPERATION                 = 11477,  -- What will you do? Nothing. Initiate Voidwatch operation. View alignment values. Examine atmacite. Read up on the Voidwatch.
        USE_YES_NO                                                            = 11478,  -- Use %? Yes. No.
        YOU_DO_NOT_POSSESS_THE_NECESSARY_TO_INITIATE                          = 11479,  -- You do not possess the % necessary to initiate a Voidwatch operation here.
        A_FIEND_MATERIALIZES_FROM_THE_PLANAR_RIFT                             = 11480,  -- A fiend materializes from the planar rift!
        CURRENT_SPECTRAL_ALIGNMENT_BLUE_REWARD_QUANTITY_RED_REWARD            = 11481,  -- Current Spectral Alignment Blue: +#% (reward quantity) Red: +#% (reward quality)
        YELLOW_EXPERIENCE_YIELD_GREEN_CRUOR_YIELD                             = 11482,  -- Yellow: +#% (experience yield) Green: +#% (cruor yield)
        ALIGNMENT_BONUSES_GRANTED_BY_ASCENT_ITEMS_WILL_BE                     = 11483,  -- Alignment bonuses granted by ascent items will be added to the final value.
        YOU_CAN_INFUSE_UP_TO_ATMACITE_AT_THIS                                 = 11484,  -- You can infuse up to # atmacite at this time.
        WHAT_WILL_YOU_DO_NOTHING_FOR_NOW_INFUSED                              = 11485,  -- What will you do? Nothing for now. Infused: % (Lv.#) Infused: % (Lv.#) Infused: % (Lv.#) Purge atmacite. Infuse atmacite. Enrich atmacite.
        INFUSE_WHICH_ATMACITE_CRUOR_NONE_FOR_NOW_LV                           = 11486,  -- Infuse which atmacite? (Cruor: #) None for now. % (Lv.#) % (Lv.#) % (Lv.#) % (Lv.#) % (Lv.#) % (Lv.#) % (Lv.#) % (Lv.#) % (Lv.#) % (Lv.#) % (Lv.#) % (Lv.#) Previous page. Next page.
        THE_LV_BESTOWS_THE_FOLLOWING_BONUSES                                  = 11487,  -- The % (Lv.#) bestows the following bonuses:
        INFUSING_THE_LV_REQUIRES_CRUOR                                        = 11488,  -- Infusing the % (Lv.#) requires # cruor.
        INFUSE_LV_YES_NO                                                      = 11489,  -- Infuse % (Lv.#)? Yes. No.
        REPLACE_LV_YES_NO                                                     = 11490,  -- Replace % (Lv.#)? Yes. No.
        EXPENDS_CRUOR_AND_IS_NOW_INFUSED_WITH_LV                              = 11491,  -- % expends # cruor and is now infused with % (Lv.#)!
        WHICH_ATMACITE_NONE_FOR_NOW_LV_LV_LV                                  = 11492,  -- [Infuse/Purge] which atmacite? None for now. % (Lv.#) % (Lv.#) % (Lv.#)
        PURGE_LV_YES_NO                                                       = 11493,  -- Purge % (Lv.#)? Yes. No.
        PURGES_THE_LV_INFUSING_LV_IN_ITS_PLACE                                = 11494,  -- % purges the % (Lv.#), infusing % (Lv.#) in its place. (Cruor expended: #)
        PURGE_LV_YES_NO_2                                                     = 11495,  -- Purge % (Lv.#)? Yes. No.
        HAS_BEEN_PURGED_OF_THE_LV                                             = 11496,  -- % has been purged of the % (Lv.#).
        YOU_DO_NOT_HAVE_ENOUGH_CRUOR_3                                        = 11497,  -- You do not have enough cruor.
        THE_ATMACITE_COULD_NOT_BE_INFUSED                                     = 11498,  -- The atmacite could not be infused...
        THE_ATMACITE_COULD_NOT_BE_PURGED                                      = 11499,  -- The atmacite could not be purged...
        YOU_DO_NOT_POSSESS_ANY_ATMACITE_CAPABLE_OF                            = 11500,  -- You do not possess any atmacite capable of enrichment.
        ENRICH_WHICH_ATMACITE_CRUOR_NONE_FOR_NOW_LV                           = 11501,  -- Enrich which atmacite? (Cruor: #) None for now. % (Lv.#): # % (Lv.#): # % (Lv.#): # % (Lv.#): # % (Lv.#): # % (Lv.#): # % (Lv.#): # % (Lv.#): # % (Lv.#): # % (Lv.#): # % (Lv.#): # % (Lv.#): # Previous page. Next page.
        ENRICHING_THE_WILL_PRODUCE_THE_FOLLOWING                              = 11502,  -- Enriching the % will produce the following:
        ENRICHING_THE_FROM_LEVEL_TO_LEVEL_REQUIRES_CRUOR                      = 11503,  -- Enriching the % from level # to level # requires # cruor.
        ENRICH_YES_NO                                                         = 11504,  -- Enrich %? Yes. No.
        YOUR_HAS_BEEN_ENRICHED_TO_LEVEL_CRUOR_EXPENDED                        = 11505,  -- Your % has been enriched to level #! (Cruor expended: #)
        THE_HAS_BEEN_ENRICHED_TO_ITS_MAXIMUM_LEVEL                            = 11506,  -- The % has been enriched to its maximum level!
        THE_ATMACITE_S_ENRICHMENT_LEVEL_FAILED_TO_RISE                        = 11507,  -- The atmacite's enrichment level failed to rise...
        READ_UP_ON_WHAT_NOTHING_FOR_NOW_VOIDWATCH                             = 11508,  -- Read up on what? Nothing for now. Voidwatch Ops. How to participate. %. Stratum abyssite. Alignment. Atmacite. Periapt.
        THE_VOIDWATCH_IS_A_FELLOWSHIP_OF_MEN_AND                              = 11509,  -- The Voidwatch is a fellowship of men and women come together to defend the world from extradimensional invaders called Voidwalkers. Driven only by an insatiable appetite for destruction, these fell horrors roam the space between dimensions, ever seeking to enter and plunge Vana'diel into chaos.
        FACED_WITH_THE_RISK_OF_MASS_INVASION_VOIDWATCH                        = 11510,  -- Faced with the risk of mass invasion, Voidwatch leaders devised a strategy wherein potential threats are preemptively neutralized. This act was made possible through the discovery of voidstones, magicked objects capable of rendering Voidwalkers visible to be summarily dispatched.
        SUCH_EFFORTS_TO_STEM_THE_RISE_OF_VOIDWALKERS                          = 11511,  -- Such efforts to stem the rise of Voidwalkers, collectively dubbed Voidwatch Operations, or Ops for short, take place in the vicinity of planar rifts--weak points in the fabric of space.
        A_SINGLE_PERSON_MAY_INITIATE_A_VOIDWATCH_OPERATION                    = 11512,  -- A single person may initiate a Voidwatch operation, at which time Voidwatcher status will be bestowed upon all qualifying party and alliance members, allowing them to commence battle with the target Voidwalker.
        VOIDWATCH_OPS_ARE_SUBJECT_TO_A_TIME_LIMIT                             = 11513,  -- Voidwatch Ops are subject to a time limit. Exceed this limit and Voidwatcher status will be revoked for all involved, bringing the confrontation to an end. Individuals straying too far from the site of battle, too, will find themselves relieved of the status.
        KNOW_ALSO_THAT_THOSE_WHO_TAKE_ON_THE                                  = 11514,  -- Know also that those who take on the burden of the Voidwatcher become temporarily isolated and unable to receive aid from the outside world. Such is the arduous nature of transdimensional encounters.
        INITIATING_A_VOIDWATCH_OPERATION_REQUIRES_A_VOIDSTONE_AS              = 11515,  -- Initiating a Voidwatch operation requires a voidstone, as well as a stratum abyssite attuned to a particular planar rift.
        ONLY_ONE_PERSON_NEEDS_TO_BE_IN_POSSESSION                             = 11516,  -- Only one person needs to be in possession of these objects for all party and alliance members to participate.
        HOWEVER_THERE_EXISTS_A_NUMBER_OF_PARTICIPATION_CONDITIONS             = 11517,  -- However, there exists a number of participation conditions that must be observed.
        WHEN_AN_OPERATION_COMMENCES_A_SINGLE_VOIDSTONE_WILL                   = 11518,  -- When an operation commences, a single voidstone will be expended for all who possess it. These combatants will have the opportunity to improve their spoils by manipulating spectral alignment values during battle.
        CONVERSELY_THOSE_NOT_POSSESSING_THEIR_OWN_VOIDSTONE_WILL              = 11519,  -- Conversely, those not possessing their own voidstone will be limited in the spoils they can obtain.
        THE_VOIDSTONE_IS_A_MAGICKED_OBJECT_WHICH_WHEN                         = 11520,  -- The voidstone is a magicked object which, when coupled with stratum abyssite, is capable of rendering Voidwalkers visible.
        ONLY_A_SINGLE_COMBATANT_NEED_POSSESS_A_VOIDSTONE                      = 11521,  -- Only a single combatant need possess a voidstone to allow all party and alliance members to participate in a Voidwatch operation. Those without one, however, will find their spoils limited in both quantity and quality.
        AS_A_SINGLE_VOIDSTONE_IS_AUTOMATICALLY_EXPENDED_WHEN                  = 11522,  -- As a single voidstone is automatically expended when the battle commences, it is recommended that you keep stock of your inventory.
        THOSE_WISHING_TO_OBTAIN_THE_STONES_SHOULD_SPEAK                       = 11523,  -- Those wishing to obtain the stones should speak to a Voidwatch officer, who is charged with issuing a set quantity at fixed intervals.
        STRATUM_ABYSSITE_ARE_DYNAMIC_STONES_CAPABLE_OF_EVOLUTION              = 11524,  -- Stratum abyssite are dynamic stones capable of evolution. By absorbing the energies emitted by felled Voidwalkers, they become attuned with other planar rifts.
        AFTER_DEFEATING_YOUR_QUARRY_PRESENT_YOUR_STONE_TO                     = 11525,  -- After defeating your quarry, present your stone to an atmacite refiner--specialists in the study of otherworld geology--to have its properties determined.
        STRATUM_ABYSSITE_GROWTH_OCCURS_INDEPENDENTLY_OF_VOIDSTONES_AND        = 11526,  -- Stratum abyssite growth occurs independently of voidstones, and the latter is not required to trigger development.
        EACH_DIMENSION_IS_COMPOSED_OF_ITS_OWN_EXISTENTIAL                     = 11527,  -- Each dimension is composed of its own existential spectrum to which objects of that world are aligned. The act of rendering a Voidwalker visible is essentially an act of aligning oneself to its existential spectrum.
        WHILE_VOIDWATCHERS_ARE_ABLE_TO_FOR_ALL_PRACTICAL                      = 11528,  -- While Voidwatchers are able to, for all practical purposes, interact with such creatures, they in fact fall short of full alignment. Symptoms of this imperfect state can be observed in the limited quantity and quality of spoils normally yielded by Voidwalkers.
        COMPENSATING_MEASURES_HOWEVER_EXIST_WHICH_ALLOW_COMBATANTS_TO         = 11529,  -- Compensating measures, however, exist which allow combatants to more closely attune themselves with their extradimensional foe. One such method involves the use of alignment-enhancing artifacts known as ascent items.
        ALIGNMENT_VALUES_RAISED_THROUGH_ASCENT_ITEMS_WILL_REMAIN              = 11530,  -- Alignment values raised through ascent items will remain in place until such time as a riftworn pyxis is opened at the end of a successful operation.
        THOSE_PARTICIPATING_IN_VOIDWATCH_OPS_ARE_RECOMMENDED_TO               = 11531,  -- Those participating in Voidwatch Ops are recommended to plan ahead in order to make effective use of ascent items.
        ALIGNMENT_VALUES_CAN_ALSO_BE_RAISED_IN_THE                            = 11532,  -- Alignment values can also be raised in the midst of battle by striking at enemy weaknesses, causing their existential attunement to shift to your advantage.
        BLOWS_CAN_BE_DEALT_WITH_ABILITIES_SUCH_AS                             = 11533,  -- Blows can be dealt with abilities such as weapon skills and magic spells, and your choice of weakness and the manner in which you strike it will determine which hue of the alignment spectrum is affected.
        THE_EXISTENTIAL_SPECTRUM_IS_COMPRISED_OF_FIVE_LIGHTS                  = 11534,  -- The existential spectrum is comprised of five lights (blue, red, yellow, green, and white), each of which influences reward yield.
        THE_PRECISE_WORKINGS_OF_EACH_LIGHT_CAN_BE                             = 11535,  -- The precise workings of each light can be reviewed when examining your current alignment values.
        UPON_THE_SUCCESSFUL_CONCLUSION_OF_BATTLE_THE_ALIGNMENT                = 11536,  -- Upon the successful conclusion of battle, the alignment bonus as granted by ascent items and the exploitation of enemy weaknesses are combined to determine the spoils.
        BE_FOREWARNED_VOIDWALKERS_ARE_HIGHLY_GUILEFUL_BEINGS_AND              = 11537,  -- Be forewarned: Voidwalkers are highly guileful beings and will not suffer the same weakness being struck twice. Combatants must be on constant watch for any changes that may occur during the course of battle.
        ATMACITE_IS_THE_PHYSICAL_AGGLOMERATION_OF_A_MONSTER                   = 11538,  -- Atmacite is the physical agglomeration of a monster's soul, and a vessel for its feral instincts. By infusing atmacite to one's body using %, it is possible to enhance one's battle prowess.
        BE_AWARE_HOWEVER_THAT_POWERS_GRANTED_BY_ATMACITE                      = 11539,  -- Be aware, however, that powers granted by atmacite can be tapped only when engaged in a Voidwatch operation.
        ATMACITE_IS_RESILIENT_AND_WILL_NOT_BE_EXPENDED                        = 11540,  -- Atmacite is resilient and will not be expended in the infusion process.
        FURTHERMORE_INFUSED_ATMACITE_WILL_REMAIN_IN_PLACE_UNTIL               = 11541,  -- Furthermore, infused atmacite will remain in place until voluntarily purged.
        AS_THE_CONFIGURATION_OF_ATMACITE_IS_NOT_POSSIBLE                      = 11542,  -- As the configuration of atmacite is not possible during an operation, be sure to see to your battle preparations ahead of time.
        CRUOR_CAN_BE_USED_TO_ENRICH_ATMACITE_ENHANCING                        = 11543,  -- Cruor can be used to enrich atmacite, enhancing its potency. The amount of cruor required for enrichment and the resultant properties vary with atmacite.
        ATMACITE_CAN_BE_ENRICHED_IN_STAGES_TO_A                               = 11544,  -- Atmacite can be enriched in stages to a maximum of level #.
        ALL_VOIDWATCHERS_ARE_URGED_TO_MAKE_ATMACITE_ENRICHMENT                = 11545,  -- All Voidwatchers are urged to make atmacite enrichment a priority, for they might just mean the difference between life and death.
        PERIAPT_ARE_LUCKY_CHARMS_THAT_GRANT_MYRIAD_BENEFICIAL                 = 11546,  -- Periapt are lucky charms that grant myriad beneficial effects ranging from improved vitality to general upturns in fortune.
        ESPECIALLY_SOUGHT_AFTER_ARE_THOSE_BESTOWING_TEMPORARY_ITEMS           = 11547,  -- Especially sought after are those bestowing temporary items at the commencement of an operation, granting combatants a distinct advantage against the enemy.
        ALTHOUGH_THEIR_ACQUISITION_CAN_ONLY_BE_DESCRIBED_AS                   = 11548,  -- Although their acquisition can only be described as arduous, the benefits make them well worth the effort.
        EXPENDS_AND_INCREASES_SPECTRAL_ALIGNMENT_BY_CURRENT_VALUE             = 11549,  -- % expends % and increases [blue/red/yellow/green] spectral alignment by #%! Current value: +#%
        EXPENDS_AND_INCREASES_SPECTRAL_ALIGNMENT_BY_CURRENT_VALUE_2           = 11550,  -- % expends % and increases [blue/red/yellow/green] spectral alignment by #%! Current value: +#%
        SPECTRAL_ALIGNMENT_CANNOT_BE_FURTHER_RAISED_WITH_CURRENT              = 11551,  -- [Blue/Red/Yellow/Green] spectral alignment cannot be further raised with %. Current value: +#%
